import itertools

def calculate_combinations(brick_set):
    combinations = list(itertools.combinations(brick_set, 3))
    return combinations

def calculate_rarity(combinations):
    rarity = {}
    for combination in combinations:
        sorted_combination = tuple(sorted(combination))
        if sorted_combination in rarity:
            rarity[sorted_combination] += 1
        else:
            rarity[sorted_combination] = 1
    return rarity

def calculate_paygrade(rarity):
    paygrade = {}
    for combination, count in rarity.items():
        if count == 1:
            paygrade[combination] = "Rare"
        elif count <= 5:
            paygrade[combination] = "Uncommon"
        else:
            paygrade[combination] = "Common"
    return paygrade

def main():
    brick_set = [915, 103, 765, 2, 4]
    combinations = calculate_combinations(brick_set)
    rarity = calculate_rarity(combinations)
    paygrade = calculate_paygrade(rarity)
    for combination, grade in paygrade.items():
        print(f"Combination: {combination}, Paygrade: {grade}")

if __name__ == "__main__":
    main()
